* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family:
    -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  background: #f4f5f7;
  color: #172b4d;
}

.board {
  max-width: 1000px;
  margin: 0 auto;
  padding: 24px;
}

.board h1 {
  margin-bottom: 16px;
}

.columns {
  display: flex;
  gap: 16px;
  align-items: flex-start;
}

.column {
  background: #ebecf0;
  border-radius: 8px;
  padding: 12px;
  flex: 1;
  min-height: 200px;
}

.column h2 {
  font-size: 14px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin: 0 0 12px 0;
  color: #5e6c84;
}

.card-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
  min-height: 40px;
}

.card {
  background: white;
  border-radius: 6px;
  padding: 10px 12px;
  box-shadow: 0 1px 2px rgba(9, 30, 66, 0.25);
  cursor: grab;
  user-select: none;
}

.card:active {
  cursor: grabbing;
}

